import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { useAuth } from '../context/AuthContext';
import './Layout.css';

const AdminNav = [
  { path: '/admin', label: 'Dashboard', icon: '▣' },
  { path: '/admin/guards', label: 'Guards', icon: '👮' },
  { path: '/admin/attendance', label: 'Logs', icon: '≡' }
];

const GuardNav = [
  { path: '/guard', label: 'Dashboard', icon: '⌂' },
  { path: '/guard/attendance', label: 'My Logs', icon: '≡' }
];

export default function Layout({ children }) {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const [menuOpen, setMenuOpen] = useState(false);
  const navItems = isAdmin ? AdminNav : GuardNav;

  const handleLogout = () => {
    setMenuOpen(false);
    logout();
    toast.success('Session terminated. Security access revoked.');
    navigate('/login');
  };

  // Close dropdown when clicking outside
  const handleOverlayClick = () => setMenuOpen(false);

  return (
    <div className="layout">
      {menuOpen && (
        <div
          style={{ position: 'fixed', inset: 0, zIndex: 999 }}
          onClick={handleOverlayClick}
        />
      )}

      <header className="header">
        <div className="brand">
          <div className="brand-icon">🛡</div>
          <div>
            <div className="brand-name">NammaRaksham</div>
            <div className="brand-sub">{isAdmin ? 'Command Center' : 'Guard Portal'}</div>
          </div>
        </div>

        <nav className="desktop-nav">
          {navItems.map(item => (
            <NavLink
              key={item.path}
              to={item.path}
              end={item.path === '/admin' || item.path === '/guard'}
              className={({ isActive }) => `desktop-nav-item ${isActive ? 'active' : ''}`}
            >
              <span className="desktop-nav-icon">{item.icon}</span>
              <span className="desktop-nav-label">{item.label}</span>
            </NavLink>
          ))}
          <button className="desktop-nav-item logout-desktop" onClick={handleLogout}>
            <span className="desktop-nav-icon">⏻</span>
            <span className="desktop-nav-label">Logout</span>
          </button>
        </nav>

        <div className="header-right">
          <div className="user-chip" onClick={() => setMenuOpen(!menuOpen)}>
            <div className={`user-avatar ${isAdmin ? 'admin' : ''}`}>
              {user?.name?.[0]?.toUpperCase()}
            </div>
            <div className="user-info">
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{isAdmin ? '● Admin' : '● Guard'}</div>
            </div>
          </div>
          {menuOpen && (
            <div className="dropdown">
              <div className="dropdown-item">
                <span style={{ color: 'var(--text-muted)' }}>{user?.email}</span>
              </div>
              {user?.employeeId && (
                <div className="dropdown-item">
                  <span style={{ color: 'var(--text-muted)' }}>ID: {user?.employeeId}</span>
                </div>
              )}
              <div className="dropdown-divider" />
              <button className="dropdown-item dropdown-logout" onClick={handleLogout}>
                ⏻ Logout
              </button>
            </div>
          )}
        </div>
      </header>

      <main className="main-content">
        {children}
      </main>

      <nav className="bottom-nav">
        {navItems.map(item => (
          <NavLink
            key={item.path}
            to={item.path}
            end={item.path === '/admin' || item.path === '/guard'}
            className={({ isActive }) => `bottom-nav-item ${isActive ? 'active' : ''}`}
          >
            <span className="bottom-nav-icon">{item.icon}</span>
            <span className="bottom-nav-label">{item.label}</span>
          </NavLink>
        ))}
        <button className="bottom-nav-item" onClick={handleLogout}>
          <span className="bottom-nav-icon">⏻</span>
          <span className="bottom-nav-label">Logout</span>
        </button>
      </nav>
    </div>
  );
}
